query:
-- 查看orders表中的总记录数
SELECT COUNT(*) as totalOrders FROM orders;

-- 查看classDate不为空的记录数
SELECT COUNT(*) as ordersWithClassDate FROM orders WHERE classDate IS NOT NULL AND classDate != '';

-- 查看前10条订单的关键字段
SELECT id, deliveryCity, classDate, paymentDate, teacherFee, transportFee 
FROM orders 
ORDER BY id DESC 
LIMIT 10;

